-- J13a — Advertising Engine\n-- Phase 1: Ad placements, campaigns, targeting, scheduling\n\n-- ── Ad placements (zones in app where ads can appear) ────────────────────────────\n\ncreate table if not exists ad_placements (\n  id uuid primary key default gen_random_uuid(),\n  name text not null, -- \"banner_header\", \"card_sponsor\", \"push_notification\"\n  description text,\n  platform text not null, -- 'web', 'mobile', 'push'\n  dimensions text, -- '728x90', '300x250', '1200x400'\n  estimated_monthly_impressions int,\n  available boolean default true,\n  created_at timestamp default now(),\n  updated_at timestamp default now()\n);\n\ninsert into ad_placements (name, description, platform, dimensions, estimated_monthly_impressions) values\n  ('banner_header', 'Header banner in app', 'web', '1200x100', 50000),\n  ('card_sponsor', 'Sponsored card in service list', 'web', '350x300', 30000),\n  ('push_notification', 'Opt-in push notification', 'mobile', 'text', 20000)\non conflict do nothing;\n\n-- ── Advertisers (companies buying ad space) ────────────────────────────────────\n\ncreate table if not exists advertisers (\n  id uuid primary key default gen_random_uuid(),\n  name text not null unique,\n  description text,\n  contact_email text not null,\n  contact_phone text,\n  website text,\n  logo_url text,\n  status text default 'pending', -- pending, approved, suspended\n  monthly_budget_eur int, -- in cents\n  created_at timestamp default now(),\n  updated_at timestamp default now()\n);\n\ncreate index idx_advertisers_status on advertisers(status);\ncreate index idx_advertisers_email on advertisers(contact_email);\n\n-- ── Ad campaigns (advertiser's campaign with budget, targeting, schedule) ───────\n\ncreate table if not exists ad_campaigns (\n  id uuid primary key default gen_random_uuid(),\n  advertiser_id uuid not null references advertisers(id) on delete cascade,\n  name text not null,\n  description text,\n  creative_title text,\n  creative_description text,\n  creative_image_url text,\n  creative_cta_text text default 'En savoir plus',\n  creative_cta_url text,\n  \n  -- Targeting\n  target_regions text[] default '{}', -- commune_ids or department_codes\n  target_min_population int,\n  target_max_population int,\n  \n  -- Scheduling\n  start_date date not null,\n  end_date date not null,\n  time_windows text[] default '{\"00:00-23:59\"}', -- \"08:00-18:00\"\n  frequency_cap_per_user int default 1, -- impressions per user per day\n  \n  -- Budget\n  total_budget_eur int not null, -- in cents\n  daily_budget_eur int, -- in cents (optional, for pacing)\n  spent_eur int default 0,\n  \n  -- Placements\n  placements uuid[] not null, -- ad_placement_ids\n  \n  -- Status\n  status text default 'draft', -- draft, active, paused, completed, rejected\n  approved_at timestamp,\n  approved_by_id uuid references auth.users(id),\n  \n  created_at timestamp default now(),\n  updated_at timestamp default now()\n);\n\ncreate index idx_campaigns_advertiser on ad_campaigns(advertiser_id);\ncreate index idx_campaigns_status on ad_campaigns(status);\ncreate index idx_campaigns_dates on ad_campaigns(start_date, end_date);\n\n-- ── Ad impressions & clicks (metrics) ──────────────────────────────────────────\n\ncreate table if not exists ad_impressions (\n  id uuid primary key default gen_random_uuid(),\n  campaign_id uuid not null references ad_campaigns(id) on delete cascade,\n  placement_id uuid not null references ad_placements(id),\n  collectivity_id uuid not null references collectivities(id),\n  user_id uuid references auth.users(id),\n  \n  -- Tracking\n  impression_id text unique, -- client-side unique ID to prevent double-counting\n  clicked boolean default false,\n  click_time timestamp,\n  \n  -- User data (aggregated, not stored individually for RGPD)\n  device_type text, -- 'mobile', 'desktop', 'tablet'\n  browser text,\n  \n  created_at timestamp default now()\n);\n\ncreate index idx_impressions_campaign on ad_impressions(campaign_id);\ncreate index idx_impressions_collectivity on ad_impressions(collectivity_id);\ncreate index idx_impressions_created_at on ad_impressions(created_at);\n\n-- ── Ad consent (GDPR: citizen opt-in for push ads) ───────────────────────────────\n\ncreate table if not exists ad_consent (\n  id uuid primary key default gen_random_uuid(),\n  user_id uuid not null references auth.users(id) on delete cascade,\n  collectivity_id uuid not null references collectivities(id),\n  \n  consent_type text not null, -- 'push_ads', 'analytics_tracking'\n  consented boolean not null,\n  \n  created_at timestamp default now(),\n  updated_at timestamp default now()\n);\n\ncreate unique index idx_consent_user_collectivity_type on ad_consent(user_id, collectivity_id, consent_type);\ncreate index idx_consent_user on ad_consent(user_id);\n\n-- ── Monetization dashboard data (pre-aggregated for performance) ────────────────\n\ncreate table if not exists monetization_metrics (\n  id uuid primary key default gen_random_uuid(),\n  collectivity_id uuid not null references collectivities(id) on delete cascade,\n  date date not null,\n  \n  -- Subscription revenue\n  subscription_revenue_eur int default 0, -- in cents\n  \n  -- Ad revenue\n  ad_impressions int default 0,\n  ad_clicks int default 0,\n  ad_revenue_eur int default 0, -- in cents (CPM-based)\n  \n  -- Share to collectivity\n  collectivity_share_eur int default 0, -- 50% of ad revenue\n  \n  created_at timestamp default now(),\n  updated_at timestamp default now()\n);\n\ncreate unique index idx_metrics_collectivity_date on monetization_metrics(collectivity_id, date);\ncreate index idx_metrics_collectivity on monetization_metrics(collectivity_id);\n\n-- ── RLS: Row-level security ──────────────────────────────────────────────────────\n\nalter table ad_placements enable row level security;\nalter table advertisers enable row level security;\nalter table ad_campaigns enable row level security;\nalter table ad_impressions enable row level security;\nalter table ad_consent enable row level security;\nalter table monetization_metrics enable row level security;\n\n-- Placements: public read\ncreate policy \"placements_public_read\" on ad_placements\n  for select using (available);\n\n-- Advertisers: read only status=approved\ncreate policy \"advertisers_public_read\" on advertisers\n  for select using (status = 'approved');\n\n-- Campaigns: read by advertiser + admins\ncreate policy \"campaigns_advertiser_read\" on ad_campaigns\n  for select using (\n    auth.jwt() ->> 'role' = 'service_role' or\n    advertiser_id in (select id from advertisers where contact_email = auth.jwt() ->> 'email')\n  );\n\n-- Impressions: service role only\ncreate policy \"impressions_service_all\" on ad_impressions\n  for all using (auth.jwt() ->> 'role' = 'service_role');\n\n-- Consent: users can read/write their own consent\ncreate policy \"consent_user_read\" on ad_consent\n  for select using (user_id = auth.uid());\n\ncreate policy \"consent_user_write\" on ad_consent\n  for insert with check (user_id = auth.uid());\n\ncreate policy \"consent_user_update\" on ad_consent\n  for update using (user_id = auth.uid());\n\n-- Metrics: admins of collectivity + service role\ncreate policy \"metrics_admin_read\" on monetization_metrics\n  for select using (\n    auth.jwt() ->> 'role' = 'service_role' or\n    exists (\n      select 1 from user_roles ur\n      where ur.user_id = auth.uid()\n        and ur.collectivity_id = monetization_metrics.collectivity_id\n        and ur.role_level >= 2\n    )\n  );\n\n-- ── Functions ─────────────────────────────────────────────────────────────────────\n\n-- Calculate CPM (cost per mille impressions)\ncreate or replace function calculate_cpm(impressions int, budget_eur int) returns int as $$\nbegin\n  if impressions = 0 then return 0; end if;\n  return (budget_eur * 1000) / impressions;\nend;\n$$ language plpgsql immutable;\n\n-- Calculate collectivity revenue share from ads\ncreate or replace function calculate_collectivity_share(ad_revenue_eur int) returns int as $$\nbegin\n  -- 50% share to collectivities\n  return (ad_revenue_eur * 50) / 100;\nend;\n$$ language plpgsql immutable;\n\n-- ── Grants ─────────────────────────────────────────────────────────────────────────\n\ngrant select on ad_placements to authenticated, anon;\ngrant select on ad_campaigns to authenticated;\ngrant all on ad_campaigns to service_role;\ngrant all on ad_impressions to service_role;\ngrant all on advertisers to service_role;\ngrant select, insert, update on ad_consent to authenticated;\ngrant all on ad_consent to service_role;\ngrant select on monetization_metrics to authenticated;\ngrant all on monetization_metrics to service_role;\n"